void ImageBgEffect::release_current_texture() {
    if (!loaded_texture_key.empty()) {
        auto it = s_texture_pool.find(loaded_texture_key);
        if (it != s_texture_pool.end()) {
            it->second.ref_count--;
            if (it->second.ref_count <= 0) {
                glDeleteTextures(1, &it->second.id);
                s_texture_pool.erase(it);
            }
        }
        loaded_texture_key = "";
        base_image_id = 0;
        current_vram_res = 0;
    }
}

// ==============================================================================
// CPU BILINEAR DOWNSAMPLER
// ==============================================================================
static void cpu_downscale_bilinear(unsigned char*& data, int& w, int& h, int channels, int max_dim) {
    if (w <= max_dim && h <= max_dim) return;

    float ratio = std::min((float)max_dim / w, (float)max_dim / h);
    int nw = static_cast<int>(w * ratio);
    int nh = static_cast<int>(h * ratio);

    unsigned char* ndata = (unsigned char*)malloc(nw * nh * channels);
    if (!ndata) return; 

    for (int y = 0; y < nh; ++y) {
        for (int x = 0; x < nw; ++x) {
            float gx = x / ratio;
            float gy = y / ratio;
            int gxi = static_cast<int>(gx);
            int gyi = static_cast<int>(gy);
            
            float tx = gx - gxi;
            float ty = gy - gyi;
            float c00 = (1 - tx) * (1 - ty);
            float c10 = tx * (1 - ty);
            float c01 = (1 - tx) * ty;
            float c11 = tx * ty;

            for (int c = 0; c < channels; ++c) {
                int p00 = data[(gyi * w + gxi) * channels + c];
                int p10 = (gxi + 1 < w) ? data[(gyi * w + gxi + 1) * channels + c] : p00;
                int p01 = (gyi + 1 < h) ? data[((gyi + 1) * w + gxi) * channels + c] : p00;
                int p11 = ((gxi + 1 < w) && (gyi + 1 < h)) ? data[((gyi + 1) * w + gxi + 1) * channels + c] : p00;

                float val = p00 * c00 + p10 * c10 + p01 * c01 + p11 * c11;
                ndata[(y * nw + x) * channels + c] = static_cast<unsigned char>(std::min(std::max(val, 0.0f), 255.0f));
            }
        }
    }
    
    stbi_image_free(data);
    data = ndata;
    w = nw;
    h = nh;
}

