void ImageBgEffect::start_async_load(const std::string& path, int target_res) {
    if (is_loading) return; 
    
    if (worker_thread.joinable()) worker_thread.join();

    is_loading = true;
    abort_load = false;

    worker_thread = std::thread([this, path, target_res]() {
        // ИСПРАВЛЕНИЕ: Отключаем аппаратный флип, так как он уже есть в image_vert.glsl
        stbi_set_flip_vertically_on_load(false); 
        
        int w, h, c;
        unsigned char* d = stbi_load(path.c_str(), &w, &h, &c, 0); 
        
        if (abort_load) {
            if (d) stbi_image_free(d);
            is_loading = false;
            return;
        }

        if (d) {
            cpu_downscale_bilinear(d, w, h, c, target_res);
            
            std::lock_guard<std::mutex> lock(async_mutex);
            if (async_data) free(async_data); 
            
            async_data = d;
            async_w = w;
            async_h = h;
            async_c = c;
            async_path = path;
            async_target_res = target_res;
        } else {
            std::cerr << "[Image Bg] Async load failed for: " << path << std::endl;
        }

        is_loading = false;
    });
}

