void ImageBgEffect::check_async_results() {
    std::lock_guard<std::mutex> lock(async_mutex);
    if (!async_data) return; 

    std::string new_key = async_path + "_" + std::to_string(async_target_res);
    release_current_texture(); 

    glGenTextures(1, &base_image_id);
    glBindTexture(GL_TEXTURE_2D, base_image_id);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S, GL_CLAMP_TO_EDGE);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T, GL_CLAMP_TO_EDGE);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_LINEAR_MIPMAP_LINEAR);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_LINEAR);

    GLenum format = (async_c == 3) ? GL_RGB : GL_RGBA;
    GLenum internal_format = (async_c == 3) ? GL_RGB8 : GL_RGBA8;
    
    // ИСПРАВЛЕНИЕ КОРРУПЦИИ: Исходные данные от процессора ВСЕГДА 8-битные!
    GLenum type = GL_UNSIGNED_BYTE;

    // Оптимизация VRAM: Заставляем видеокарту сжать 8-битные данные в 16 бит
    if (optimize_vram) {
        internal_format = (async_c == 3) ? GL_RGB565 : GL_RGBA4;
    }

    glPixelStorei(GL_UNPACK_ALIGNMENT, 1); 
    glTexImage2D(GL_TEXTURE_2D, 0, internal_format, async_w, async_h, 0, format, type, async_data);
    glGenerateMipmap(GL_TEXTURE_2D);
    glPixelStorei(GL_UNPACK_ALIGNMENT, 4);

    base_image_w = static_cast<float>(async_w);
    base_image_h = static_cast<float>(async_h);
    current_vram_res = async_target_res;
    loaded_texture_key = new_key;

    s_texture_pool[new_key] = {base_image_id, base_image_w, base_image_h, current_vram_res, 1};
    
    // Очистка оперативной памяти
    free(async_data); 
    async_data = nullptr;
}


void ImageBgEffect::process_textures(uint32_t screen_w, uint32_t screen_h) {
    if (!m_core || base_image_path.empty()) return;

    int required_res = max_texture_size; 
    
    if (dynamic_lod) {
        // Улучшенный расчет требуемого качества:
        // Если картинка занимает лишь часть экрана (Contain), учитываем scale.
        // Если это фон (Cover), scale не добавляет физических пикселей на монитор.
        float needed_pixels = std::max(screen_w, screen_h);
        if (fill_mode == 1) needed_pixels *= scale; 
        
        int lod_tiers[] = {256, 512, 1024, 2048, 4096, 8192, 16384};
        for (int tier : lod_tiers) {
            if (tier >= needed_pixels) {
                required_res = tier;
                break;
            }
        }
    }
    required_res = std::min(required_res, max_texture_size);

    std::string fp = base_image_path;
    if (fp[0] != '/') {
        const char* bundle_path = m_core->get_bundle_path(get_name());
        if (bundle_path && bundle_path[0] != '\0') fp = std::string(bundle_path) + "/" + fp;
    }

    std::string target_key = fp + "_" + std::to_string(required_res);

    if (base_image_pending || (target_key != loaded_texture_key)) {
        auto it = s_texture_pool.find(target_key);
        if (it != s_texture_pool.end()) {
            release_current_texture();
            it->second.ref_count++;
            base_image_id = it->second.id;
            base_image_w = it->second.w;
            base_image_h = it->second.h;
            current_vram_res = it->second.res;
            loaded_texture_key = target_key;
            base_image_pending = false;
            return;
        }

        if (!is_loading) {
            start_async_load(fp, required_res);
            base_image_pending = false;
        }
    }

    check_async_results();
}

void ImageBgEffect::render(uint32_t width, uint32_t height, float dt) {
    process_textures(width, height);
    time += dt; 

    if (!base_image_id) return;

    glUseProgram(program);
    if (u_time != -1) glUniform1f(u_time, time);
    if (u_resolution != -1) glUniform2f(u_resolution, static_cast<float>(width), static_cast<float>(height));
    if (u_fill_mode != -1) glUniform1i(u_fill_mode, fill_mode);
    if (u_scale != -1) glUniform1f(u_scale, scale);
    if (u_offset != -1) glUniform2fv(u_offset, 1, &offset[0]);
    if (u_rotation != -1) glUniform1f(u_rotation, rotation);
    if (u_brightness != -1) glUniform1f(u_brightness, brightness);
    if (u_contrast != -1) glUniform1f(u_contrast, contrast);
    if (u_saturation != -1) glUniform1f(u_saturation, saturation);
    if (u_tint_color != -1) glUniform3fv(u_tint_color, 1, &tint_color[0]);
    if (u_tint_intensity != -1) glUniform1f(u_tint_intensity, tint_intensity);
    if (u_blur_radius != -1) glUniform1f(u_blur_radius, blur_radius);

    glActiveTexture(GL_TEXTURE0);
    glBindTexture(GL_TEXTURE_2D, base_image_id);
    if (u_base_image != -1) glUniform1i(u_base_image, 0);
    if (u_base_image_resolution != -1) glUniform2f(u_base_image_resolution, base_image_w, base_image_h);

    glDisable(GL_DEPTH_TEST);
    glBindVertexArray(vao);
    glDrawArrays(GL_TRIANGLE_STRIP, 0, 4); 
    glBindVertexArray(0);
    glActiveTexture(GL_TEXTURE0);
    glEnable(GL_DEPTH_TEST);
}

void ImageBgEffect::on_cleanup() {
    if (program) { glDeleteProgram(program); program = 0; }
    if (vao) { glDeleteVertexArrays(1, &vao); vao = 0; }
    release_current_texture(); 
}

